def research_agent_loop(stack, query, max_turns=10):
    conversation = [{'role': 'user', 'content': query}]

    for turn in range(max_turns):
        response = stack.chat(
            conversation,
            tools=['serpapi_search'],
            tool_choice='auto'
        )

        conversation.append({
            'role': 'assistant',
            'content': response.content,
            'tool_calls': response.tool_calls
        })

        # Execute tools and append results
        if response.tool_calls:
            for tool_call in response.tool_calls:
                result = execute_tool(tool_call)
                conversation.append({
                    'role': 'tool',
                    'content': result,
                    'tool_call_id': tool_call.id
                })

        if response.finish_reason == 'stop':
            return response.content

    return 'Research exceeded turn limit'

def store_research_sources(stack, query, sources):
    documents = []
    for source in sources:
        doc = {
            'content': source['text'],
            'metadata': {
                'url': source['url'],
                'date': source['date'],
                'title': source['title']
            }
        }
        stack.memory_bank.store(doc)

    # Retrieve relevant context for next turn
    context = stack.memory_bank.retrieve(query, limit=5)
    return context

