def vex_research_guardrails(stack_output, sources):
    verification = verify(
        text=stack_output.content,
        sources=[s['content'] for s in sources],
        metadata=[{'recency': s['date']} for s in sources],
        check_types=[
            'recency_checks',
            'bias_detection',
            'claim_accuracy'
        ],
        risk_profile='medium',
        domain='academic_research'
    )

    if not verification.passed:
        return {
            'status': 'rejected',
            'issues': verification.failures,
            'corrected': verification.suggested_fix
        }

    return {'status': 'approved', 'output': stack_output.content}

